struct Vector3 {
    float x, y, z;

    Vector3 operator+(const Vector3& other) const { return {x + other.x, y + other.y, z + other.z}; }
    Vector3 operator-(const Vector3& other) const { return {x - other.x, y - other.y, z - other.z}; }
    Vector3 operator*(float scalar) const { return {x * scalar, y * scalar, z * scalar}; }
    float dot(const Vector3& other) const { return x * other.x + y * other.y + z * other.z; }
    float lengthSq() const { return x * x + y * y + z * z; }
    float length() const { return std::sqrt(lengthSq()); }
    Vector3 normalized() const {
        float len = length();
        if (len > 0) return {x / len, y / len, z / len};
        return {0, 0, 0};
    }
};

// Function to convert degrees to radians
float toRadians(float degrees) {
    return degrees * (M_PI / 180.0f);
}

// Function to calculate forward vector from yaw and pitch (in degrees)
// Assumes a coordinate system where:
// +X is right, +Y is up, +Z is forward.
// Yaw rotates around the Y-axis (left/right look).
// Pitch rotates around the X-axis (up/down look).
Vector3 getForwardVector(float yaw, float pitch) {
    float radYaw = toRadians(yaw);
    float radPitch = toRadians(pitch);

    float cosPitch = std::cos(radPitch);
    float sinPitch = std::sin(radPitch);
    float cosYaw = std::cos(radYaw);
    float sinYaw = std::sin(radYaw);

    Vector3 forward;
    forward.x = cosYaw * cosPitch; // X-component (right/left)
    forward.y = sinPitch;          // Y-component (up/down)
    forward.z = sinYaw * cosPitch; // Z-component (forward/backward)

    return forward.normalized();
}


