void GameServer::sendGameStateToClients() {
    // Create a buffer for the game state packet
    char buffer[MAX_PACKET_SIZE];
    ServerToClient_GameStateHeader header;
    header.header.type = PACKET_TYPE_GAME_STATE;
    header.header.playerId = 0; // Not used for game state header
    header.numPlayers = static_cast<uint32_t>(playerStates.size());

    if (header.numPlayers == 0) {
        return; // No players to send state for
    }

    // Copy header to buffer
    memcpy(buffer, &header, sizeof(ServerToClient_GameStateHeader));
    size_t offset = sizeof(ServerToClient_GameStateHeader);

    // Append each player's state
    for (const auto& pair : playerStates) {
        if (offset + sizeof(PlayerState) > MAX_PACKET_SIZE) {
            std::cerr << "Warning: Game state packet too large, truncating player data." << std::endl;
            break; // Stop adding players if buffer is full
        }
        memcpy(buffer + offset, &(pair.second), sizeof(PlayerState));
        offset += sizeof(PlayerState);
    }

    // Send the combined game state to all known clients
    for (const auto& pair : clientAddresses) {
        // Only send to clients who have sent a packet recently
        if (playerStates.count(pair.first)) {
            const PlayerState& player = playerStates[pair.first];
            auto now = std::chrono::steady_clock::now();
            auto time_since_last_packet = std::chrono::duration_cast<std::chrono::seconds>(now - player.lastPacketTime);
            if (time_since_last_packet.count() > 30) { // If inactive for 30 seconds, consider disconnected
                // Optional: remove player from maps if truly disconnected
                // For simplicity, we keep them, but won't update their lastPacketTime unless they send a packet.
            }
        }
        // Actually send
        sendto(serverSocket, buffer, offset, 0, (struct sockaddr*)&pair.second, sizeof(pair.second));
    }
}

void GameServer::run() {
    char recvBuffer[MAX_PACKET_SIZE];
    sockaddr_in clientAddr;
    socklen_t clientAddrLen = sizeof(clientAddr);

    auto lastGameTickTime = std::chrono::steady_clock::now();

    while (true) {
        // --- Receive packets ---
        // Use select for non-blocking receive with a timeout
        fd_set read_fds;
        FD_ZERO(&read_fds);
        FD_SET(serverSocket, &read_fds);

        timeval timeout;
        timeout.tv_sec = 0;
        timeout.tv_usec = 1000; // 1ms timeout to keep loop responsive

        int select_status = select(static_cast<int>(serverSocket) + 1, &read_fds, NULL, NULL, &timeout);

        if (select_status > 0 && FD_ISSET(serverSocket, &read_fds)) {
            int bytesReceived = recvfrom(serverSocket, recvBuffer, MAX_PACKET_SIZE, 0,
                                         (struct sockaddr*)&clientAddr, &clientAddrLen);

            if (bytesReceived == -1 || bytesReceived == 0) {
                // Error or no data
#ifdef _WIN32
                int error = WSAGetLastError();
                if (error != WSAEWOULDBLOCK) { // WSAEWOULDBLOCK is normal for non-blocking with no data
                    std::cerr << "recvfrom failed with error: " << error << std::endl;
                }
#else
                if (errno != EWOULDBLOCK && errno != EAGAIN) { // EWOULDBLOCK/EAGAIN normal for non-blocking
                    std::cerr << "recvfrom failed with error: " << errno << std::endl;
                }
#endif
            } else {
                handlePacket(recvBuffer, bytesReceived, clientAddr);
            }
        } else if (select_status == -1) {
#ifdef _WIN32
            std::cerr << "select failed with error: " << WSAGetLastError() << std::endl;
#else
            std::cerr << "select failed with error: " << errno << std::endl;
#endif
        }
        // else select_status == 0 means timeout, no data, just continue

        // --- Game Logic and State Broadcast ---
        auto currentTime = std::chrono::steady_clock::now();
        auto elapsedTime = std::chrono::duration_cast<std::chrono::milliseconds>(currentTime - lastGameTickTime);

        if (elapsedTime >= GAME_TICK_RATE_MS) {
            sendGameStateToClients();
            lastGameTickTime = currentTime;
        }

        // A small sleep to prevent busy-waiting if there's no network activity and the game tick rate is low
        // This is handled sufficiently by the select timeout for this example.
        // For production, consider `std::this_thread::sleep_for` if the loop spins too fast.
    }
}

